class Queue:
    def __init__(self):
        self.deque = []

    def merge(self, q1, q2):
        if not q1.deque or not q2.deque:
            return

        new_deque = [q1.deque[0] + q2.deque[0]]
        q1.deque = q1.deque[1:]; q2.deque = q2.deque[1:]
        return new_deque

    def dequeue(self):
        return self.deque.pop(0)

q1 = Queue(); q2 = Queue()
q1.deque = [1, 2]; q2.deque = [3, 4]
merged_deque = q1.merge(q1, q2)
print(merged_deque)  # Output: [5]

solutions.cpp:
class Queue {
    std::deque<int> deque;

public:
    void merge(Queue& q1, Queue& q2) {
        if (q1.deque.empty() || q2.deque.empty())
            return;

        new_deque.push_back(q1.deque.front() + q2.deque.front());
        q1.deque.pop_front(); q2.deque.pop_front();
    }

    int dequeue() {
        return deque.front();
    }
};

int main() {
    Queue q1, q2;
    q1.deque.push_back(1); q1.deque.push_back(2);
    q2.deque.push_back(3); q2.deque.push_back(4);
    q1.merge(q1, q2);
    std::cout << q1.dequeue() << std::endl;  // Output: 5
    return 0;
}
